import React from 'react';

function PricingTable() {
  const pricingItems = [
    {
      category: "Hàng phổ thông",
      items: "Quần áo, giày dép, đồ gia dụng",
      price: "260.000 VNĐ/kg",
    },
    {
      category: "Thực phẩm chức năng",
      items: "Sữa, Đồ em bé",
      price: "280.000 VNĐ/kg",
    },{
      category: "Mỹ phẩm",
      items: "Nước hoa, Túi xách hiệu",
      price: "300.000 VNĐ/kg",
    },
    {
      category: "Hàng điện tử cao cấp",
      items: "Laptop, iPhone",
      price: "Liên hệ báo giá",
    },
  ];

  return (
    <section className="py-16 px-4 md:px-0 bg-gray-100" id="pricing">
      <div className="container mx-auto text-center">
        <h2 className="text-4xl font-extrabold text-primary-dark">Bảng giá chi tiết</h2>
        <p className="mt-4 text-lg text-gray-700">Mức giá ưu đãi cho từng loại mặt hàng.</p>

        <div className="mt-12 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {pricingItems.map((item, index) => (
            <div key={index} className="bg-white p-6 rounded-lg shadow-xl border border-gray-200 flex flex-col justify-between">
              <div>
                <h3 className="text-2xl font-bold text-primary-dark mb-2">{item.category}</h3>
                <p className="text-gray-600 text-sm italic">({item.items})</p>
              </div>
              <div className="mt-4">
                <p className="text-3xl font-extrabold text-primary-accent">{item.price}</p>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-10 p-6 bg-orange-100 border-l-4 border-orange-500 text-orange-800 rounded-lg max-w-2xl mx-auto shadow-md">
          <p className="text-xl font-bold">Ưu đãi đặc biệt:</p>
          <p className="text-lg mt-2">Giảm ngay xuống <span className="font-extrabold text-primary-dark">250.000đ/kg</span> cho kiện hàng trên 5kg!</p>
        </div>
      </div>
    </section>
  );
}

export default PricingTable;
